import React, { useState } from 'react';
import axios from 'axios';
import Editor from '@monaco-editor/react';
import jsPDF from 'jspdf';
import html2canvas from 'html2canvas';
import { 
  Upload, FileCode, ShieldCheck, RefreshCw, 
  BarChart3, Terminal, Activity, ShieldAlert, Download, Settings
} from 'lucide-react';

import RiskProfile from './components/RiskProfile';
import StatisticsTab from './components/StatisticsTab';

function App() {
  const [activeTab, setActiveTab] = useState("analysis");
  const [viewMode, setViewMode] = useState("original");
  const [loading, setLoading] = useState(false);
  const [file, setFile] = useState(null);
  const [code, setCode] = useState("// Load a PHP payload to begin...");
  const [results, setResults] = useState(null);

  const handleFileUpload = (e) => {
    const uploadedFile = e.target.files[0];
    if (uploadedFile) {
      setFile(uploadedFile);
      const reader = new FileReader();
      reader.onload = (e) => setCode(e.target.result);
      reader.readAsText(uploadedFile);
    }
  };

  const analyzeMalware = async () => {
    if (!file) return;
    setLoading(true);
    const formData = new FormData();
    formData.append("file", file);
    try {
      const response = await axios.post("http://localhost:8000/scan", formData);
      setResults(response.data.results);
    } catch (error) {
      alert("Backend Connection Offline");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex h-screen bg-[#020617] text-slate-300 font-sans overflow-hidden">
      
      {/* SIDEBAR NAVIGATION */}
      <aside className="w-72 bg-[#0f172a] border-r border-slate-800 flex flex-col p-6 z-50">
        <div className="flex items-center gap-3 mb-12">
          <div className="bg-blue-600 p-2 rounded-lg shadow-lg shadow-blue-500/20">
            <ShieldCheck className="text-white" size={24} />
          </div>
          <div>
            <h1 className="text-xl font-black text-white tracking-tight uppercase">PHPSentinel</h1>
            <p className="text-[9px] text-blue-500 font-black tracking-widest uppercase">Research v2.6</p>
          </div>
        </div>

        <nav className="flex flex-col gap-2 flex-1">
          <button onClick={() => setActiveTab("analysis")} className={`flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-bold transition-all ${activeTab === 'analysis' ? 'bg-blue-600/10 text-blue-400 border border-blue-600/20 shadow-[0_0_15px_rgba(37,99,235,0.1)]' : 'text-slate-500 hover:bg-slate-800/50 hover:text-slate-300'}`}>
            <Terminal size={18} /> Threat Detection
          </button>
          <button onClick={() => setActiveTab("stats")} className={`flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-bold transition-all ${activeTab === 'stats' ? 'bg-blue-600/10 text-blue-400 border border-blue-600/20 shadow-[0_0_15px_rgba(37,99,235,0.1)]' : 'text-slate-500 hover:bg-slate-800/50 hover:text-slate-300'}`}>
            <BarChart3 size={18} /> Model Analytics
          </button>
          <div className="mt-8 pt-8 border-t border-slate-800/50">
            <p className="text-[10px] text-slate-600 font-black uppercase tracking-widest px-4 mb-4">Operations</p>
            <label className="flex items-center gap-3 px-4 py-3 text-slate-500 hover:text-slate-300 cursor-pointer text-sm font-bold transition-all">
              <Upload size={18} />
              <span>{file ? "Change File" : "Upload PHP"}</span>
              <input type="file" className="hidden" onChange={handleFileUpload} accept=".php" />
            </label>
            <button onClick={analyzeMalware} disabled={loading} className="w-full mt-4 flex items-center justify-center gap-2 py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl text-sm font-black shadow-lg shadow-blue-900/20 transition-all active:scale-95 disabled:opacity-50">
              {loading ? <RefreshCw className="animate-spin" size={16} /> : <Activity size={16} />}
              {loading ? "SCANNING..." : "SCAN PAYLOAD"}
            </button>
          </div>
        </nav>

        <div className="bg-slate-900/50 p-4 rounded-2xl border border-slate-800/50">
          <div className="flex items-center gap-2 text-blue-400 mb-2 font-black text-[10px] uppercase">
             <ShieldAlert size={14} /> Intelligence Status
          </div>
          <p className="text-[11px] text-slate-500 leading-relaxed font-medium">Model: CodeBERT-PHP-v2<br/>Confidence: Calibrated<br/>Status: Online</p>
        </div>
      </aside>

      {/* MAIN WORKSPACE */}
      <main className="flex-1 flex flex-col min-w-0 bg-[#020617] relative">
        {/* Subtle Background Glow */}
        <div className="absolute top-0 right-0 w-[500px] h-[500px] bg-blue-600/5 blur-[120px] pointer-events-none rounded-full"></div>
        
        <header className="h-20 flex items-center justify-between px-8 border-b border-slate-800/50 backdrop-blur-sm z-10">
          <div className="flex items-center gap-4">
            <h2 className="text-sm font-black text-slate-400 uppercase tracking-widest">
              {activeTab === 'analysis' ? 'Malware Semantic Analysis' : 'Model Performance Matrix'}
            </h2>
            {file && <span className="px-3 py-1 bg-slate-800 text-blue-400 text-[10px] font-mono rounded-full border border-slate-700">{file.name}</span>}
          </div>
          {results && (
            <button onClick={() => window.print()} className="flex items-center gap-2 px-4 py-2 bg-slate-800 hover:bg-slate-700 text-slate-300 rounded-lg text-xs font-bold border border-slate-700 transition-all">
              <Download size={14} /> Export Report
            </button>
          )}
        </header>

        <section className="flex-1 p-8 overflow-y-auto">
          {activeTab === "analysis" ? (
            <div className="grid grid-cols-12 gap-8 h-full max-w-[1600px] mx-auto w-full">
              {/* CODE VIEW */}
              <div className="col-span-12 xl:col-span-8 flex flex-col gap-4">
                <div className="bg-[#0f172a] rounded-[2rem] border border-slate-800 overflow-hidden flex flex-col shadow-2xl h-[75vh]">
                  <div className="px-6 py-4 border-b border-slate-800 flex justify-between items-center bg-slate-900/30">
                    <div className="flex items-center gap-4">
                      <div className="flex gap-1.5">
                        <div className="w-2.5 h-2.5 rounded-full bg-red-500/20 border border-red-500/40"></div>
                        <div className="w-2.5 h-2.5 rounded-full bg-yellow-500/20 border border-yellow-500/40"></div>
                        <div className="w-2.5 h-2.5 rounded-full bg-green-500/20 border border-green-500/40"></div>
                      </div>
                      <span className="text-[10px] font-mono text-slate-500 uppercase font-black tracking-widest border-l border-slate-700 pl-4">{viewMode}</span>
                    </div>
                    <div className="flex bg-slate-950 rounded-lg p-1 border border-slate-800">
                      <button onClick={() => setViewMode("original")} className={`px-4 py-1.5 text-[10px] font-black rounded-md transition-all ${viewMode === 'original' ? 'bg-slate-800 text-blue-400 shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}>RAW SOURCE</button>
                      <button onClick={() => setViewMode("normalized")} className={`px-4 py-1.5 text-[10px] font-black rounded-md transition-all ${viewMode === 'normalized' ? 'bg-slate-800 text-blue-400 shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}>DEOBFUSCATED</button>
                    </div>
                  </div>
                  <div className="flex-1">
                    <Editor
                      theme="vs-dark"
                      defaultLanguage="php"
                      value={results ? (viewMode === "original" ? results.original_code : results.normalized_code) : code}
                      options={{ 
                        minimap: { enabled: false }, 
                        fontSize: 14, 
                        fontFamily: "'Fira Code', monospace",
                        padding: { top: 20 },
                        readOnly: true,
                        scrollbar: { vertical: 'hidden', horizontal: 'hidden' }
                      }}
                    />
                  </div>
                </div>
              </div>

              {/* RISK PANEL */}
              <div className="col-span-12 xl:col-span-4 h-full">
                {results ? <RiskProfile data={results} /> : (
                  <div className="h-full border-2 border-dashed border-slate-800 rounded-[2rem] flex flex-col items-center justify-center p-12 text-center opacity-40">
                    <ShieldCheck size={48} className="text-slate-600 mb-6" />
                    <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest">Inference Pending</h3>
                    <p className="text-xs text-slate-600 mt-2 max-w-[180px]">Load a script and initialize the scan to map semantic risk.</p>
                  </div>
                )}
              </div>
            </div>
          ) : (
            <StatisticsTab />
          )}
        </section>
      </main>
    </div>
  );
}

export default App;
